// ─── Seed Function ─────────────────────────────────────────────────────────────

async function seed() {
  console.log(`Seeding ${EXERCISES.length} exercises...`);

  let inserted = 0;
  let updated = 0;
  let failed = 0;

  for (const ex of EXERCISES) {
    try {
      const values = {
        name: ex.name,
        movementPattern: ex.movementPattern,
        bodyRegion: ex.bodyRegion ?? null,
        unilateral: ex.unilateral ?? false,
        primaryMuscle: ex.primaryMuscle,
        secondaryMuscles: ex.secondaryMuscles,
        equipment: ex.equipment,
        difficultyLevel: ex.difficultyLevel,
        intentTags: ex.intentTags,
        jointStressProfile: ex.jointStressProfile,
        tags: ex.tags ?? [],
        clusterId: ex.clusterId ?? null,
        easierVariations: ex.easierVariations,
        harderVariations: ex.harderVariations,
        description: ex.description,
        isActive: true,
      };

      const result = await db
        .insert(exerciseLibrary)
        .values(values)
        .onConflictDoUpdate({
          target: exerciseLibrary.name,
          set: {
            movementPattern: values.movementPattern,
            bodyRegion: values.bodyRegion,
            unilateral: values.unilateral,
            primaryMuscle: values.primaryMuscle,
            secondaryMuscles: values.secondaryMuscles,
            equipment: values.equipment,
            difficultyLevel: values.difficultyLevel,
            intentTags: values.intentTags,
            jointStressProfile: values.jointStressProfile,
            tags: values.tags,
            clusterId: values.clusterId,
            easierVariations: values.easierVariations,
            harderVariations: values.harderVariations,
            description: values.description,
          },
        })
        .returning({ id: exerciseLibrary.id });

      if (result.length > 0) {
        inserted++;
      }
    } catch (err: any) {
      console.error(`Failed to insert/update ${ex.name}:`, err.message);
      failed++;
    }
  }

  // Final stats from DB
  const statsResult = await db.execute(
    sql`
      SELECT
        COUNT(*)::int as total,
        COUNT(DISTINCT cluster_id)::int as clusters,
        COUNT(DISTINCT movement_pattern)::int as patterns,
        COUNT(CASE WHEN unilateral = true THEN 1 END)::int as unilateral_count
      FROM exercise_library
      WHERE is_active = true
    `
  );

  const patternResult = await db.execute(
    sql`
      SELECT movement_pattern, COUNT(*)::int as count
      FROM exercise_library
      WHERE is_active = true
      GROUP BY movement_pattern
      ORDER BY count DESC
    `
  );

  const stats = statsResult.rows?.[0] ?? statsResult[0] ?? {};
  console.log(`\n✓ Done: ${inserted} inserted/updated, ${failed} failed`);
  console.log(`\n📊 Library Stats:`);
  console.log(`  Total exercises: ${(stats as any).total}`);
  console.log(`  Unique clusters: ${(stats as any).clusters}`);
  console.log(`  Movement patterns: ${(stats as any).patterns}`);
  console.log(`  Unilateral exercises: ${(stats as any).unilateral_count}`);

  console.log(`\n📋 By Movement Pattern:`);
  const rows = patternResult.rows ?? patternResult;
  for (const row of rows as any[]) {
    console.log(`  ${row.movement_pattern}: ${row.count}`);
  }

  process.exit(0);
}

seed().catch((err) => {
  console.error("Seed failed:", err);
  process.exit(1);
});
